            'MetricsSinkInterface / ErrorSinkInterface' => 'A sink driver never transports telemetry itself — it only declares capabilities and renders the collector\'s exporter fragment for its backend. Switching grafana → datadog is a one-line config change; app code never touches a vendor SDK. Generated collector config always binds the OTLP receiver to loopback-only, includes memory_limiter+batch, and disk-buffers exporter retries.',
            'BoundedSpool'      => 'Crash-safe, byte-capped on-disk FIFO behind error delivery — never blocks the emit path, never grows unbounded (drops oldest on overflow), survives a mid-write crash.',
            'MessageScrubber'   => 'Redacts emails/tokens/JWTs/card numbers from error messages before they leave the process — the same defense-in-depth posture as Secrets\' SecretValue and Analytics\' PiiRedactor.',
            'AuditHashChain (deploy ledger)' => 'Same chaining technique as vortos-auth\'s audit log, applied to Deploy\'s LifecycleEvents — every deploy/rollback/reconcile is tamper-evidently recorded.',
            'HeartbeatEmitterInterface' => 'Dead-man\'s-switch push — detected by absence, off-host. One of the 3 detectors vortos-health\'s DetectorIndependenceDoctorCheck requires in production.',
            'DeployMarker'      => 'Dashboard annotation linking a regression to the exact deploy (buildId, gitSha, imageDigest) — carries no secrets/PII. Buffered via OutboxMarkerEmitter, never emitted synchronously during a deploy.',
            'Slo / SloRegistry' => 'A declared, validated SLO resource (objective must be in (0,1), enforced at construction) — single source of truth both dashboards and Alerts\' SloBurnCondition read from, instead of drifting hand-maintained dashboard config.',
            'Sentry error sink'  => 'SentryErrorSink (#[AsDriver(\'sentry\')]) ships alongside the GlitchTip driver — same envelope ingest protocol, reads OBSERVABILITY_SENTRY_DSN. Select the active error sink with OBSERVABILITY_ERROR_SINK (null|glitchtip|sentry); the "selected error sink" is aliased to ErrorSinkInterface so consumers inject whatever the operator configured.',
            'Configurable collector bind' => 'The generated OTLP receiver still binds loopback (127.0.0.1) by default (sidecar sharing the app netns), but --bind / OBSERVABILITY_COLLECTOR_BIND lets a separate worker container emit to a shared collector on a private Docker network (0.0.0.0). The tracing stub OTLP endpoint now defaults to 127.0.0.1:4318 to match the loopback sidecar.',
        ],
        'config' => [
            'OBSERVABILITY_METRICS_SINK' => 'grafana (default) | null — which metrics sink the collector forwards to.',
            'OBSERVABILITY_ERROR_SINK'   => 'null (default) | glitchtip | sentry — the active error sink.',
            'OBSERVABILITY_SENTRY_DSN / _GLITCHTIP_DSN' => 'Ingest DSN for the selected error sink (read at drain time, never stored/logged).',
            'OBSERVABILITY_COLLECTOR_BIND' => 'OTLP receiver bind host: 127.0.0.1 (sidecar) | 0.0.0.0 (shared collector on a private network).',
        ],
        'commands' => [
            'vortos:observability:list' => 'List available observability template stacks',
            'vortos:observability:publish' => 'Publish templates with --stack, --force, and --dry-run',
            'vortos:observability:collector' => 'Generate collector config + a docker-compose.collector.yaml fragment from the selected MetricsSinkInterface driver. The fragment mounts a named volume for the exporter file_storage queue and ships an init sidecar that chowns it to the collector uid (10001) before the collector starts (a fresh named volume is root-owned and would crash-loop the non-root collector); the collector waits for the init via service_completed_successfully. Flags: --sink, --bind (receiver host), --storage-dir, --force, --dry-run.',
            'vortos:observability:audit:verify' => 'Verify the deploy audit ledger hash chain for an environment — fails at the first broken link.',
            'vortos:observability:audit:export' => 'Stream a signed deploy-audit export (NDJSON or CSV). Flags: --env, --format',
            'vortos:observability:heartbeat' => 'Send one dead-man heartbeat ping.',
            'vortos:observability:markers:drain' => 'Drain the buffered deploy-marker outbox to the configured emitter.',
        ],
    ],

    'foundation' => [
        'package'     => 'vortos/vortos-foundation',
        'description' => 'Health checks, pre-flight diagnostics, boot error rendering, worker mode service resetter, and compile-time interface binding via #[DefaultImpl] and #[OverrideImpl]. If vortos-health is installed, that package\'s tri-state probe aggregator serves /health/* instead, and BridgeLegacyHealthChecksPass auto-wraps every HealthCheckInterface below as a probe — zero migration needed.',
        'provides'    => [
            'HealthRegistry'         => 'Register HealthCheckInterface implementations. Exposed via /health/ready and /health/live (or bridged into vortos-health if that package is installed — see the health module).',
            'ServicesResetter'       => 'Calls reset() on all ResettableInterface services after each request in worker mode.',
            'DoctorRegistry'         => 'Runs all registered DoctorCheckInterface implementations. Tag with #[AsDoctor].',
            '#[AsDoctor]'            => 'Attribute to register a DoctorCheckInterface as a pre-flight diagnostic check.',
            'DoctorCheckInterface'   => 'run(): DoctorResult — implement to add a custom doctor check.',
            'BootErrorRenderer'      => 'Formats boot exceptions in CLI with human-readable hints for common failures.',
            'ContainerDumpabilityPass' => 'Always-on Foundation compiler pass (runs every compile — dev/test/prod/CI) that walks every service definition\'s arguments, properties, method-call args and factory and FAILS THE COMPILE listing EVERY non-dumpable object-instance argument at once, before Symfony\'s PhpDumper is ever reached. Prod+HTTP caches the container via PhpDumper, which cannot serialize a raw object instance as a service argument — the fix is ALWAYS to pass an inline `new Definition(Foo::class, [$scalar])` (or scalar/Reference/enum), never `new Foo($scalar)`. Enums, Reference, Definition, Parameter, Expression and the Argument\\* value objects are allowed. This class of bug otherwise only surfaces one-at-a-time on a real prod HTTP boot.',
            '#[DefaultImpl]'         => 'Compile-time attribute that creates an interface → class alias if no alias or definition already exists. Framework extensions register their bindings first, so explicit services.php registrations always take precedence over #[DefaultImpl]. Infers the target interface when the class implements exactly one app-namespace interface; specify explicitly with #[DefaultImpl(MyInterface::class)] when the class implements multiple. Errors are thrown immediately. Sets the vortos.default_impl.bindings container parameter.',
            '#[OverrideImpl]'        => 'Compile-time attribute that unconditionally replaces any existing alias or definition — including bindings registered by framework extensions. Use when app code needs to win over a framework default without adding an explicit alias to services.php. Runs after DefaultImplCompilerPass (priority 0 vs 5). Duplicate overrides (two classes claiming the same interface) and resolution errors are COLLECTED and thrown as a single exception so all misconfigurations surface at once. Sets the vortos.override_impl.bindings container parameter.',
        ],
        'config'   => null,
        'commands' => [
            'vortos:health'  => 'Check all registered HealthCheckInterface services. Flags: --json (machine-readable output)',
            'vortos:doctor'  => 'Run all registered pre-flight diagnostic checks. Flags: --fail-on-warning (exit 1 on warnings)',
            'debug:bindings' => 'List all interface → class bindings registered by #[DefaultImpl]. Add -v to include file paths. #[OverrideImpl] bindings are visible via debug:container.',
        ],
    ],

    'setup' => [
