    'ops_kit' => [
        'package'     => 'vortos/vortos-ops-kit',
        'description' => 'The swappable-driver pattern shared by every operations package below (Deploy, Backup, Secrets, Alerts, Observability, Analytics, Migration, IaC, Pipeline) — ports, drivers, capability negotiation, registries, zero runtime reflection. Not something you configure directly unless authoring a NEW driver for one of those concerns.',
        'provides'    => [
            '#[AsDriver(key)]'        => 'Marks a class as the driver for a port. Key must be lower-kebab (^[a-z][a-z0-9-]*$), validated at compile time, not runtime.',
            'DriverInterface'         => 'Base interface every port extends. Single required method: capabilities(): CapabilityDescriptor.',
            'TaggedDriverRegistry'    => 'Base class for a concern\'s typed registry — lazy key→driver lookup backed by a compile-time ServiceLocator. get(key) throws UnknownDriverException listing every key that IS registered.',
            'CapabilityDescriptor / RequiredCapabilities' => 'CapabilityValidator::assertSatisfies() reconciles what a driver declares vs what a strategy/config needs — mismatches fail at CONFIG time with an actionable message, never silently at runtime.',
            'ConformanceTestCase (TCK)' => 'Universal PHPUnit base every driver test extends — 6 built-in tests, plus assertRejectsUnsupportedCapability()/assertHonestlyUnsupported() helpers for proving a driver refuses loudly rather than silently no-opping an unsupported operation.',
            'AgnosticismLintTestCase / AgnosticismRule' => 'A PHPUnit test + PHPStan rule that fails if a provider name (caddy, kubernetes, posthog, betterstack, etc.) leaks outside a Driver\\ namespace — keeps core engine code provider-agnostic.',
        ],
        'config'   => null,
        'commands' => [
            'vortos:make:driver' => 'Scaffold a driver + its conformance test for a concern. Args: <concern> <name>. Options: --port, --tck, --tag, --namespace, --split (also scaffold a full installable Composer package — this is how out-of-tree drivers like vortos-deploy-k8s and vortos-analytics-posthog are built).',
        ],
    ],

    'secrets' => [
        'package'     => 'vortos/vortos-secrets',
        'description' => 'Redact-by-construction secret values, envelope encryption with off-host key custody, and policy-driven two-phase rotation. NOT the same as Security\'s SecretsProvider (simple env-var lookup) — this is the operational secrets layer used by Deploy and Backup. Used for credential/payload encryption, not for general app config values.',
        'provides'    => [
            'SecretValue'             => 'fromString(plaintext): self. reveal(): string is the ONLY method that returns the plaintext — call it as late as possible. __toString()/var_dump()/print_r()/json_encode() all render "***"; the plaintext lives in a private static WeakMap, never an instance property, so even var_export()-style reflection finds nothing. wipe() zeroizes and permanently disables reveal() (throws SecretAlreadyWipedException after). Serializing a SecretValue throws — it must never be.',
            'EnvelopeCipher'          => 'XChaCha20-Poly1305 AEAD payload encryption. generateDataKey()/encryptPayload()/decryptPayload() — a tampered ciphertext or wrong key throws DecryptionFailedException, never returns partial/garbage plaintext.',
            'KeyProviderInterface'    => 'wrap(DataKey)/unwrap(WrappedKey) — off-host key custody. Driver: age (X25519 sealed-box). wrap() only ever needs the PUBLIC key (safe to bake into a build image); unwrap() reads the PRIVATE identity from an env var at use-time, never from a tracked file. Accepts the standard age formats age-keygen emits — bech32 recipient age1… and identity AGE-SECRET-KEY-1… — as well as raw base64 X25519 (Bech32 + AgeKeyCodec, full checksum/length validation, fail-closed). The AgeKeyProvider ctor arg is $publicKey (was $publicKeyBase64).',
            'SecretsProviderInterface'=> 'get/put/rotate/list/versions. Drivers: env, file, age. list() returns key NAMES only, never values — presence checks never require revealing anything.',
            'RotationManager'        => 'rotateIfDue(key, policy, now) — decides whether due, policy-driven. forceRotate() — explicit operator action regardless of due-date. Two-phase: old AND new versions both valid during the grace window.',
            'SecretsPreflight'       => 'Diffs RequiredSecrets against what a provider actually has. Feeds deploy:doctor — a deploy missing a required secret fails before touching infrastructure.',
            'Default provider binding' => 'SecretsProviderInterface now aliases to EnvSecretsProvider by default — cross-package consumers (Deploy\'s SshKeyCredentialProvider) resolve it with zero app wiring.',
            'config/secrets.php (required-secrets surface)' => 'RequiredSecrets is built by RequiredSecretsFactory from config/secrets.php — return a list<SecretReference> (or a Closure). This is what makes secrets:preflight / deploy:doctor\'s secret gate meaningful, without overriding the service.',
        ],
        'config'   => [
            'config/secrets.php' => 'return [ new SecretReference(new SecretKey(\'DATABASE_URL\'), required: true, description: \'...\'), ... ];  // list<SecretReference> or Closure',
            'VORTOS_SECRETS_STORE_PATH / _AGE_PUBLIC_KEY / _AGE_IDENTITY' => 'File store path + age key custody (public key age1…/base64 baked in build; private identity AGE-SECRET-KEY-1…/base64 read from env at use-time).',
            'VORTOS_SECRETS_ENVIRONMENT_DRIVERS / _DEFAULT_DRIVER' => 'Optional env→driver map for secrets:preflight, e.g. "production:env,staging:vault" (default driver env). Lets --env=<environment> resolve to a driver.',
        ],
        'commands' => [
            'secrets:list'       => 'List known secret keys (names only, never values). Flags: --env=<driver-key>, --json',
            'secrets:set'        => 'Set a secret value. Args: <key>. Flags: --env=<driver-key>, --stdin (pipe a value for CI instead of an interactive hidden prompt)',
            'secrets:rotate'     => 'Rotate a secret. Args: <key>. Flags: --env=<driver-key>, --interval, --grace, --max-age',
            'secrets:preflight'  => 'Check that every required secret is present (fail-closed CI/doctor gate). Here --env is the ENVIRONMENT name (production/staging, default production), resolved to a driver via EnvironmentProviderResolver (default env driver) — so --env=production works out of the box (no UnknownDriverException). --driver=<key> bypasses resolution. Flags: --env, --driver, --json.',
        ],
    ],

    'release' => [
        'package'     => 'vortos/vortos-release',
        'description' => 'Immutable build manifests, schema fingerprinting, the rollback-safety invariant, and coordinated semver tagging + changelogs across a split monorepo.',
        'provides'    => [
            'BuildManifest'           => 'Immutable record of one build: buildId, gitSha, imageRepository, imageDigest, targetArch, schemaFingerprint. imageRepository is the fully-qualified, lowercase OCI repo (no tag/digest); pullReference() joins it with the digest into "repo@sha256:...", the only image string a target ever pulls. Recorded append-only — a duplicate buildId throws ManifestAlreadyExistsException.',
            'AvailableMigrationSetReaderInterface' => 'Reads the migrations AVAILABLE in the build (on disk), not the applied set — the schema fingerprint recorded for a build must be the desired schema it carries, independent of what has been applied. DoctrineAvailableMigrationSetReader is the default.',
            'SchemaFingerprint'       => 'Sorted, deduplicated migration-ID set reduced to a SHA-256 hash. isSubsetOf()/relationTo() — pure, order-independent, no I/O.',
            'RollbackInvariant::evaluate()' => 'A rollback is legal only when the target build\'s schema fingerprint is a SUBSET of what\'s currently applied. Returns a RollbackDecision whose explain() names the exact missing/unknown migrations and what to do about them — used directly by Deploy\'s RollbackGuard.',
            'ConventionalSemverStrategy' => 'Computes the next version from Conventional Commits (feat:/fix:/BREAKING CHANGE:).',
        ],
        'config'   => null,
        'commands' => [
            'vortos:release:tag'       => 'Coordinated semver tagging across every vortos package. Dry-run by default. Flags: --apply, --sign, --bump=auto|patch|minor|major, --package, --undo=<tx-id>, --allow-dirty, --json',
            'vortos:release:changelog' => 'Generate changelogs from conventional commits. Flags: --package, --write, --unreleased',
            'vortos:release:record-manifest' => 'Record the immutable BuildManifest for an environment AFTER build+push and AFTER provisioning (whose vortos:migrate creates the release-ledger schema this writes into) but BEFORE deploy — this is what makes a desired build resolvable by `deploy`. Derives the schema fingerprint from the build\'s available migrations. Idempotent on build id. Recording against a DB with no ledger schema fails closed with ManifestSchemaMissingException (run vortos:migrate). Flags: --env, --repository, --digest, --git-sha, --build-id, --arch, --builder-id, --base-image-digest, --json. Emitted automatically by the generated deploy job.',
        ],
    ],

    'pipeline' => [
        'package'     => 'vortos/vortos-pipeline',
        'description' => 'Generates CI/CD workflow files from a provider-agnostic model — fully digest-pinned GitHub Actions, native ARM64 builds, multi-registry login, and OIDC instead of standing registry secrets. Does NOT run builds itself — it only generates the YAML that does. Do not hand-edit generated workflow files; change the model and regenerate.',
        'provides'    => [
            'PipelineBuilder'                   => 'Assembles stages from a PipelineDefinition + StageGate. Test/StaticAnalysis/Agnosticism/Deploy/Split always emit; other stages gated behind enabledFutureStages.',
            'PinnedAction'                      => 'Refuses construction unless sha is a full 40-char hex commit SHA — no floating @v4-style tags ever land in a generated workflow.',
            'BuildMode::Native'                 => 'Generates a matrix that builds ARM64 on a real ARM64 runner instead of QEMU emulation.',
            'ArchAssertionScript'               => 'Generates a CI step that inspects the published image manifest and fails the build if the architecture doesn\'t match what was requested.',
            'PipelineDefinition(registryProvider)' => 'Selects the CI registry login provider. Values: "ghcr" (default, uses built-in GITHUB_TOKEN + packages:write), "docker-hub" (needs DOCKER_USERNAME + DOCKER_TOKEN secrets), "gcp-artifact-registry" (needs GCP_SA_KEY secret). Each provider declares only the job permissions it actually needs — no hardcoded packages:write for non-GHCR registries.',
            'CiRegistryLoginProviderInterface'  => 'Ops Kit port (Driver\\ namespace). Implement + tag #[AsDriver(\'my-registry\')] to add a custom registry. loginStep() returns a docker/login-action ActionStep; requiredPermissions() is merged into the build job\'s permission set automatically.',
            'PipelineDefinition(oidc: true)'    => 'Requests id-token: write and exchanges a short-lived OIDC token for registry access instead of a long-lived REGISTRY_PASSWORD repository secret.',
            'Generated deploy job'              => 'Deploy-on-target: the runner opens SSH to the VPS and runs vortos:deploy:provision → vortos:release:record-manifest → deploy:doctor → deploy INSIDE the pulled image ON the VPS, attached to the app Docker network (app_network). Provision runs FIRST so its vortos:migrate creates the release-ledger schema before record-manifest writes to it (a fresh DB otherwise died with "relation does not exist"). This fixes two things at once: the control-plane commands reach the prod release-ledger DB by construction, and the arm64 image runs on the arm64 host — the runner runs only an ssh client and never `docker run`s the image (no runner/image arch mismatch). The one-shots reach Docker only through the box docker-socket-proxy via DOCKER_HOST=tcp://docker-socket-proxy:2375 (never the raw socket). Registry login is provider-driven: a real remote docker login is emitted for ghcr (GITHUB_TOKEN) / docker-hub (secrets.DOCKER_USERNAME+DOCKER_TOKEN) / gcp-artifact before the pull. runs-on: ubuntu-latest; requests id-token: write iff oidc. Posture-aware auth: OIDC path = zero standing secrets beyond GITHUB_TOKEN (SSH cert federated from the id-token via non-secret vars.*, enforced by OidcZeroStandingSecretTest); ssh-key path (oidc: false) authenticates with secrets.VORTOS_DEPLOY_SSH_KEY and forwards the age KEK VORTOS_AGE_IDENTITY (the age-encrypted store is delivered 0640 to the deploy dir, mounted ro, and read via docker run --group-add). Deploy runs local-mode on the VPS (no nested SSH). The cutover runs `docker compose up` for the color FROM INSIDE the one-shot, so the generated `docker run` also bind-mounts each runtime_env_files path read-only at its absolute path (the nested compose references them as env_file:) — B19; and when file secrets are declared (runtime_file_secret_dirs) it mkdirs+mounts the tmpfs dirs and runs vortos:deploy:materialize-file-secrets right before cutover — G8.',
            'config/pipeline.php (single source of truth)' => 'The PipelineDefinition is built by PipelineDefinitionFactory from env + an optional config/pipeline.php and injected into BOTH generate and verify — there is no longer a divergent `new PipelineDefinition()` in the commands. Configure the emitted workflow here; do not override the service.',
            'Configurable test stage'           => 'PipelineDefinition now carries testCommand, analyseCommand, testSteps (extra shell steps — migrations, vortos:contracts:check, seeds — injected after deps install), and testServiceContainers (ServiceContainer[] → db/redis/kafka sidecars rendered as GitHub `services:`). This is what lets the generated workflow BE your CI instead of a hand-written ci.yml.',
            'Configurable workflow file'        => 'workflowFilename (default ci.yml, bare *.yml name) and workflowName let you emit e.g. deploy.yml with `name: Deploy` instead of clobbering an existing ci.yml.',
        ],
        'config'   => [
            'config/pipeline.php' => 'Returns an associative array (or Closure returning one) of overrides: workflow_filename, workflow_name, test_command, analyse_command, test_steps (list of [name,run]), test_service_containers, image_repository, registry_provider, environments, php_extensions, deployment_branch (trigger + deploy-gate branch, default main), remote_deploy_dir (default /opt/vortos), app_network (default vortos-net), runtime_env_files (default [/opt/vortos/.env.prod] — MUST match config/deploy.php RuntimeServiceSpec envFiles; bind-mounted RO into the one-shot for the nested cutover compose, B19), runtime_file_secret_dirs (tmpfs dirs under /run or /dev/shm for file-shaped secrets, G8), bootstrap_steps (list of [name,run] injected into EVERY container-booting job — test/analyse/agnosticism — e.g. cp .env.example .env), emit_static_analysis / emit_agnosticism (default true; turn off stages an app lacks). Quality stages are also tri-state via the builder form of config/pipeline.php: ->staticAnalysisMode()/->agnosticismMode() take QualityMode::Enforce (default, fail on issues) / Warn (guard on tool presence, surface issues as GitHub warnings, never fail the build, skip cleanly if the tool is absent) / Off (omit the stage and drop its downstream needs). The environment matrix is a SCALAR list (matrix.environment: [production] referenced as ${{ matrix.environment }}).',
            'env'                 => 'Scalars also settable via env: PIPELINE_WORKFLOW_FILENAME, PIPELINE_WORKFLOW_NAME, PIPELINE_TEST_COMMAND, PIPELINE_ANALYSE_COMMAND, PIPELINE_IMAGE_REPOSITORY, PIPELINE_REGISTRY_PROVIDER, PIPELINE_PHP_VERSION, PIPELINE_ENVIRONMENTS, PIPELINE_DEPLOYMENT_BRANCH, PIPELINE_REMOTE_DEPLOY_DIR, PIPELINE_APP_NETWORK, PIPELINE_EMIT_STATIC_ANALYSIS/AGNOSTICISM/SBOM/SCAN_GATE/SIGN. config/pipeline.php wins over env.',
        ],
        'commands' => [
            'pipeline:generate' => 'Generate workflow files from the CONFIGURED model (config/pipeline.php + env). Flags: --emitter=github, --dry-run, --force, --json',
            'pipeline:verify'   => 'Detect drift between the configured model and the committed workflow file — wire into CI on every PR.',
            'pipeline:actions:verify' => 'Resolve every pinned GitHub Action SHA against the GitHub API; fail-closed if any pin no longer exists. Network-dependent (honours GITHUB_TOKEN); wire into CI. Flags: --json. An offline structural pin check runs in the package test suite regardless.',
        ],
    ],

    'deploy' => [
        'package'     => 'vortos/vortos-deploy (+ vortos-deploy-k8s for a Kubernetes target — see the deploy_k8s module)',
        'description' => 'A fail-closed deploy engine — content-hashed plans, swappable targets, blue-green/canary/rolling/recreate strategies, phase-gated expand/contract migration safety, Caddy edge-router cutover, zero-standing-secrets credential issuance, and multi-registry container authentication. "When in doubt, refuse, don\'t guess" — do not hand-write deploy scripts if this package is installed.',
        'provides'    => [
            'DeployPlanner::plan()'        => 'PURE — same DeployContext always produces the same content-hashed DeployPlan, no I/O. PhaseGate::assertNoPendingContract() refuses planning while a contract migration from a prior expand/contract cycle is still owed.',
            'DeployTargetInterface'        => 'plan/assertImageAvailable/migrate/release(plan, env)/rollback(plan, env)/status. There is NO push() — the CI build job is the only pusher; the target instead fail-closed-verifies the pinned image exists (assertImageAvailable) before mutating, and release/rollback take the EnvironmentName so state is env-scoped. Digest resolution is DAEMON-FIRST (OciOps): in deploy-in-image the host already pulled the image, so digestFor() runs `docker image inspect --format {{json .RepoDigests}}` over the socket-proxy (no registry tool, no credentials) and only falls back to crane/skopeo/`buildx imagetools inspect` when the image is NOT local; likewise pull() short-circuits when the digest is already present locally instead of re-authenticating. The image a target deploys comes from the plan\'s image_repository+image_digest step params (via Plan\\DesiredImage), never a hardcoded repository. Drivers: ssh-compose (in-core), k8s (separate vortos-deploy-k8s package).',
            'DeployStrategyInterface'      => 'Drivers: BlueGreenStrategy, CanaryStrategy (5/25/50/100% weighted steps + health re-check at each), RollingStrategy, RecreateStrategy. Each declares RequiredCapabilities checked against the target BEFORE planning, not mid-rollout.',
            'WorkerTopology (B20)'         => 'DeploymentDefinition property + ->workerTopology(WorkerTopology::RideColor|ExternalSupervisor) builder setter (default RideColor). All four strategies emit the supervisorctl RollWorkers phase through ONE shared WorkerRolloutPhaseFactory, gated on this: RideColor (compose-managed worker-<color> that rides the color — the ssh-compose/deploy-in-image default) emits NO RollWorkers phase; ExternalSupervisor (a persistent supervisord reachable from where the deploy runs) emits it. This fixes the "supervisorctl in a throwaway one-shot with no supervisord → exit 7" cutover failure. WorkerTopologyCheck fails deploy:doctor closed if ExternalSupervisor is declared on a deploy-in-image host.',
            'PhaseOrderPolicy'             => 'Enforces RollWorkers precedes Cutover and StageColor — violating either throws at plan time.',
            'CutoverCoordinator'           => 'Cuts over, verifies the new upstream is actually live, auto-reverts (and records why) on verification failure. Every recorded release carries a monotonic generation number for compare-and-swap against a stale reconciler.',
            'RollbackGuard::assertLegal()' => 'Consults vortos-release\'s RollbackInvariant before any rollback — refuses one that would not be schema-safe, with the exact reason.',
            'CredentialProviderInterface'  => 'issue()/lease()/assertIssuable(). Providers NEVER write secret material to disk (enforced by CredentialNoStandingSecretTest) — they return it via CredentialUse::identityMaterial()/knownHostsMaterial() and the transport layer materializes it, scoped to and wiped with the lease. Drivers: ssh-ca-oidc (300s-TTL cert minted from an OIDC token, zero standing secrets — the recommended upgrade posture), ssh-key (DEFAULT: private key + deploy_known_hosts from the encrypted store; assertIssuable fails closed if EITHER is missing, since strict host-key verification is mandatory), pull-agent (NoInboundNetwork — the target polls a signed manifest instead of being pushed to).',
            'SSH push transport'           => 'ProcessSshTransport (the concrete SshTransportInterface) shells out to ssh/scp via the audited CommandRunner with StrictHostKeyChecking=yes + an explicit known_hosts (no trust-on-first-use). SshConnectionActivator leases the credential per-deploy, materializes a 0600 key + known_hosts, activates a DeployConnectionContext that LazySshTransport reads, and wipes everything after. Bound to the 3 consumers (StepExecutor pulls repo@digest ON the VPS, MountedConfigWriter, SupervisorWorkerController) + CaddyAdminClient ONLY when VORTOS_DEPLOY_DELIVERY_MODE=push and VORTOS_DEPLOY_HOST is set.',
            'RegistryAuthStrategyInterface' => 'Ops Kit port for deploy-time container registry login. Credentials always passed via stdin, never argv. Drivers: ghcr (PatTokenCredential — username + PAT), docker-hub (BasicAuthCredential), gcp-artifact-registry (GcpServiceAccountCredential — _json_key JSON via stdin). ContainerRegistryInterface is the alias StepExecutor/SshComposeTarget inject — default binding is GhcrRegistry; rebind to switch registries.',
            'config/deploy.php IS loaded'  => 'The base DeploymentDefinitionBuilder is now produced by DeploymentDefinitionBuilderFactory, which loads config/deploy.php (a Closure(DeploymentDefinitionBuilder): DeploymentDefinitionBuilder). Previously documented but never read — you no longer override the service. Fluent surface: ->host()/registry()/ci()/secrets()/strategy()/forEnvironment(env, fn).',
            'RuntimeServiceSpec'           => 'The app\'s real runtime shape — how the blue/green app+worker containers actually run — sourced from config/deploy.php and threaded into the cutover compose (ComposeFile/ComposeProjectFactory), the single source of truth for BOTH the readiness gate and the Caddy upstream dial (EdgeConfigGenerator::fromSpec() takes the dial port from containerPort — never a hardcoded value). Builder setters: ->appCommand(list) (real server argv, e.g. frankenphp run …; NEVER a placeholder), ->workerCommand(list), ->workerTopology(RideColor|ExternalSupervisor), ->containerPort(int, default 8080 — the INTERNAL port the edge dials at app-<color>:<port>), ->envFiles(list of absolute paths), ->appEnvironment(map, e.g. SERVER_NAME), ->fileSecret(name, containerPath, hostPath?, mode?). Colors are internal-only: they expose containerPort and publish NO host ports (the standalone edge owns 80/443). Defaults match the shipped FrankenPHP stub.',
            'File-shaped secrets (G8)'     => 'For secrets that must be a FILE (e.g. a tool that only reads an RS256 key from a path), declare ->fileSecret(\'jwt_private_key\', \'/run/secrets/jwt.pem\') in config/deploy.php — prefer env-content (vortos:auth:keys:generate --emit=env) whenever possible. FileSecret host paths must be tmpfs (/run or /dev/shm). Before cutover the one-shot decrypts each from the age store to its tmpfs path (vortos:deploy:materialize-file-secrets, atomic 0400 write, revealed value wiped via the single sanctioned FileSecretDecryptor), the cutover compose bind-mounts it read-only into the color, and FileSecretsCheck fails deploy:doctor closed if a declared secret is missing from the store. Zero plaintext ever touches persistent disk. The pipeline threads the tmpfs dirs via runtime_file_secret_dirs (mkdir + RW mount into the one-shot).',
            'Commands always register (fail-loud)' => 'deploy / deploy:doctor / deploy:rollback ALWAYS appear in `bin/console list` even when vortos-release/vortos-migration are absent — they print actionable remediation and return FAILURE instead of silently vanishing. Cross-package wiring moved to DeployWiringPass (compiler pass), not load().',
            'Default PSR-18/17 HTTP client' => 'HttpClientDefaultsPass binds a Guzzle PSR-18 client + PSR-17 factories when the app has not — the Caddy/OIDC/SSH-CA/registry clients resolve out of the box. An app-provided client still wins.',
            'Pull-agent is opt-in'         => 'The pull-agent reconciler + its manifest source/verifier only register when VORTOS_DEPLOY_DELIVERY_MODE=pull (push/ssh-compose is the default). deploy:agent stays visible and fails loudly if run in push mode.',
            'ArtifactDelivery (G3)'        => 'Ships the runtime files that live OUTSIDE the image — .env.prod, docker-compose.prod.yaml, docker/** + observability/** config trees, and the age-encrypted vortos-secrets.age — to the remote deploy dir over the SSH transport. DeliveryManifest::default() declares the set; required artifacts fail closed before anything is sent; the tree is staged then swapped atomically (no partial-config window); remote paths are traversal-guarded. Perms: .env.prod ships 0600 (docker reads it as the deploy uid via --env-file); the age store ships 0640 so the deploy-in-image container (a different uid) can read it via docker run --group-add — the bytes are age ciphertext so group-read leaks no plaintext. Registered whenever push-mode SSH is wired.',
            'FirstDeployProvisioner (G4)'  => 'Pure planner behind vortos:deploy:provision — keys-if-absent → migrate --force → secrets preflight, ordered and idempotent. Key presence (JwtKeyPresence) mirrors config/auth.php: present when EITHER env-content keys (JWT_PRIVATE_KEY/JWT_PUBLIC_KEY, base64 PEM) OR file paths (JWT_*_PATH) are set, so an env-content/immutable-image deploy is never wrongly told to generate file keys into a non-writable dir. The command runs the plan via the Application.',
        ],
        'config'   => [
            'config/deploy.php'                => 'return static fn (DeploymentDefinitionBuilder $b) => $b->host(\'ssh-compose\')->registry(\'ghcr\')->strategy(\'blue-green\')->workerTopology(WorkerTopology::RideColor)->forEnvironment(\'production\', fn ($b) => $b->autoRollback(true)); — also ->fileSecret(name, containerPath) for file-shaped secrets (G8), ->containerPort()/->envFiles()/->appCommand() for the RuntimeServiceSpec.',
            'VORTOS_DEPLOY_DELIVERY_MODE'      => 'push (default) | pull — pull registers the OCI manifest source + release-key verifier + reconciler.',
